// Etap I — i18n panelu (fundament): 14 języków jak w bocie. Fala 1 pokrywa nawigację
// (etykiety pozycji po href + nazwy grup po polskim labelu) i wspólne teksty UI.
// pl = fallback (oryginalne stringi w komponentach), więc słownik pl trzyma tylko klucze ui.*.
// Wybór języka: localStorage 'panelLang' + cookie 'panel_lang' (na przyszłe fale server-side).

export const PANEL_LOCALES = [
  'pl',
  'en',
  'de',
  'es',
  'it',
  'fr',
  'pt',
  'zh',
  'ko',
  'ru',
  'uk',
  'ja',
  'ar',
  'id',
] as const;
export type PanelLocale = (typeof PANEL_LOCALES)[number];
export const DEFAULT_PANEL_LOCALE: PanelLocale = 'pl';

export function isPanelLocale(v: unknown): v is PanelLocale {
  return typeof v === 'string' && (PANEL_LOCALES as readonly string[]).includes(v);
}

// Natywne nazwy do przełącznika.
export const LOCALE_NAMES: Record<PanelLocale, string> = {
  pl: 'Polski',
  en: 'English',
  de: 'Deutsch',
  es: 'Español',
  it: 'Italiano',
  fr: 'Français',
  pt: 'Português',
  zh: '中文',
  ko: '한국어',
  ru: 'Русский',
  uk: 'Українська',
  ja: '日本語',
  ar: 'العربية',
  id: 'Bahasa Indonesia',
};

// Pierwsze wejście bez zapisu: dopasuj język przeglądarki (pl-PL→pl, pt-BR→pt, zh-CN→zh…).
export function detectBrowserLocale(): PanelLocale {
  try {
    const raw = (navigator.language || '').toLowerCase();
    const base = raw.split('-')[0];
    if (isPanelLocale(base)) return base;
  } catch {
    /* SSR / brak navigator */
  }
  return DEFAULT_PANEL_LOCALE;
}

type Dict = Record<string, string>;

